    const MOD = 1000000007
    const INF = int(^uint(0) >> 1)  // max int

    const (
        North = iota  // 0
        East          // 1
        South         // 2
        West          // 3
    )

    fmt.Println(MOD)              // 1000000007
    fmt.Println(123456789 % MOD)  // 123456789
    fmt.Println(North, East, South, West)
}

